-- Migration: Create ChangePIR (Post-Implementation Review) table
-- Generated by ent, manual execution required
-- Create the main ChangePIR table
CREATE TABLE IF NOT EXISTS change_pi_rs (
    id BIGSERIAL PRIMARY KEY,
    reviewer_id BIGINT NOT NULL,
    overall_result VARCHAR(255) DEFAULT 'successful',
    objectives_achieved BOOLEAN DEFAULT FALSE,
    success_summary TEXT,
    issues_encountered TEXT,
    lessons_learned TEXT,
    improvement_recommendations TEXT,
    actual_start_time TIMESTAMP,
    actual_end_time TIMESTAMP,
    actual_duration_minutes INT DEFAULT 0,
    rollback_performed BOOLEAN DEFAULT FALSE,
    rollback_reason TEXT,
    tenant_id BIGINT NOT NULL,
    review_date TIMESTAMP DEFAULT NOW(),
    created_at TIMESTAMP DEFAULT NOW(),
    updated_at TIMESTAMP DEFAULT NOW(),
    -- Foreign key for change relationship (M2O)
    change_pir BIGINT REFERENCES changes(id) ON DELETE
    SET NULL
);
-- Create M2M junction table for reviewer relationship
CREATE TABLE IF NOT EXISTS user_pir_reviews (
    user_id BIGINT NOT NULL,
    change_pir_id BIGINT NOT NULL,
    PRIMARY KEY (user_id, change_pir_id)
);
-- Add indexes for better query performance
CREATE INDEX IF NOT EXISTS idx_change_pi_rs_tenant_id ON change_pi_rs(tenant_id);
CREATE INDEX IF NOT EXISTS idx_change_pi_rs_reviewer_id ON change_pi_rs(reviewer_id);
CREATE INDEX IF NOT EXISTS idx_change_pi_rs_review_date ON change_pi_rs(review_date DESC);
CREATE INDEX IF NOT EXISTS idx_change_pi_rs_change_pir ON change_pi_rs(change_pir);
CREATE INDEX IF NOT EXISTS idx_change_pi_rs_overall_result ON change_pi_rs(overall_result);
CREATE INDEX IF NOT EXISTS idx_user_pir_reviews_user_id ON user_pir_reviews(user_id);
CREATE INDEX IF NOT EXISTS idx_user_pir_reviews_change_pir_id ON user_pir_reviews(change_pir_id);
COMMENT ON TABLE change_pi_rs IS '变更实施后审查表 (Post-Implementation Review)';
COMMENT ON COLUMN change_pi_rs.id IS '主键';
COMMENT ON COLUMN change_pi_rs.reviewer_id IS '审查人ID';
COMMENT ON COLUMN change_pi_rs.overall_result IS '总体结果: successful, partially_successful, failed';
COMMENT ON COLUMN change_pi_rs.objectives_achieved IS '目标是否达成';
COMMENT ON COLUMN change_pi_rs.success_summary IS '成功总结';
COMMENT ON COLUMN change_pi_rs.issues_encountered IS '遇到的问题';
COMMENT ON COLUMN change_pi_rs.lessons_learned IS '经验教训';
COMMENT ON COLUMN change_pi_rs.improvement_recommendations IS '改进建议';
COMMENT ON COLUMN change_pi_rs.actual_start_time IS '实际开始时间';
COMMENT ON COLUMN change_pi_rs.actual_end_time IS '实际结束时间';
COMMENT ON COLUMN change_pi_rs.actual_duration_minutes IS '实际持续时间（分钟）';
COMMENT ON COLUMN change_pi_rs.rollback_performed IS '是否执行了回滚';
COMMENT ON COLUMN change_pi_rs.rollback_reason IS '回滚原因';
COMMENT ON COLUMN change_pi_rs.tenant_id IS '租户ID';
COMMENT ON COLUMN change_pi_rs.review_date IS '审查日期';
COMMENT ON COLUMN change_pi_rs.change_pir IS '关联的变更ID (外键)';